mapper.update:
UPDATE posts
SET del_yn = 'Y',
deleted_at = NOW(),
deleted_id = #{userEmail}
WHERE post_id = #{postId}

mapper.delete:
DELETE FROM likes
WHERE target_code = '01'
AND target_id = #{postId}
AND user_email = #{userEmail}

mapper.select:
SELECT COUNT(*) FROM likes
WHERE target_code = '01'
AND target_id = #{postId}
AND user_email = #{userEmail}
